/// <summary>
/// jumref for journal number reference - Abhinav
/// </summary>
/// <param name = "_control"></param>
public void ETGProductionJournal_jumpref(FormStringControl _control)
{
    InventJournalTable inventJournalTable;
    InventJournalTable inventJournalTableCurr = this.dataSource(1).cursor();
    DataAreaId targetCompany;

    select firstOnly crossCompany inventJournalTable
            where inventJournalTable.JournalId == inventJournalTableCurr.ETGProductionEntityBOMJournal;

    if (inventJournalTable)
    {
        targetCompany = inventJournalTable.DataAreaId;

        changeCompany(targetCompany)
        {
            Args args = new Args();
            args.record(inventJournalTable);
            new MenuFunction(menuItemDisplayStr(InventJournalTableBOM), MenuItemType::Display).run(args);
        }
    }
}

