public void init()
{
    FormStringControl formStringControl;
    FormStringControl formStringControlsub;
    next init();

    formStringControl = this.design().controlName(formControlStr(InventJournalBOM, ETGProdEntityJournal));
    formStringControl.registerOverrideMethod(methodStr(FormStringControl, jumpRef),methodStr(ETGInventJournalBOM_ETGProductionJournal_Extension,ETGProductionJournal_jumpref));

    formStringControlsub = this.design().controlName(formControlStr(InventJournalBOM, ETGSubcontractingBOMJournal));
    formStringControlsub.registerOverrideMethod(methodStr(FormStringControl, jumpRef),methodStr(ETGInventJournalBOM_ETGProductionJournal_Extension,ETGSubcontractingJournal_jumpref));
}

/// <summary>
/// CS,DLT,SB, Allow edit after posting for two custom controls
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
public void initDatasourceAllow()
{
    next initDatasourceAllow();

    if(InventJournalTable.ETGParentEntity && InventJournalTable.posted == NoYes::Yes && ETGCanadaParameters::find().EnableBOMJournalMarking == NoYes::Yes)
    {
        InventJournalTable_ds.allowEdit(true);
        allowEditFieldsOnFormDS_W(InventJournalTable_ds, !InventJournalTable.Posted);

        InventJournalTable   InventJournalTableNew;
        changecompany(InventJournalTable.ETGParentEntity)
        {
            InventJournalTableNew = InventJournalTable::find(InventJournalTable.ETGSubcontractingBOMJournal);
        }
        boolean     enableBOMMarkingAfterPosting = InventJournalTableNew && InventJournalTableNew.ETGItemId == '';

        InventJournalTable_ds.object(fieldNum(InventJournalTable, ETGSalesId)).allowEdit(enableBOMMarkingAfterPosting);
        InventJournalTable_ds.object(fieldNum(InventJournalTable, ETGItemId)).allowEdit(enableBOMMarkingAfterPosting);
    }
}
